  ('dietitian-moex-06994', 'dietitian', 'dietitian-moex-103-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '王先生申請至某團膳公司擔任營養師工作，剛通過面試進入員工體檢階段，則下列檢查項目何者為非必 須項目？ 個人及家族史  齟齒  身高、體重  視力、色盲、聽力', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "669e3f56ea31", "answer_pdf_sha1": "44b27236efc3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 36, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-06995', 'dietitian', 'dietitian-moex-103-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '供膳員工的工作衛生習慣管理，下列何種行為是不被允許？ 同一塊砧板切熟食與生食前需要清洗  不可用手直接接觸食品 所有的熟食必須蓋好    工作時不用手抓、摸頭髮', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "669e3f56ea31", "answer_pdf_sha1": "44b27236efc3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 37, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-06996', 'dietitian', 'dietitian-moex-103-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '何謂critical limit？ 控制界線  矯正點  重要控制點  風險評估', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "669e3f56ea31", "answer_pdf_sha1": "44b27236efc3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 38, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-06997', 'dietitian', 'dietitian-moex-103-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '有關素食種類的定義，下列敘述何者錯誤？ 全素或純素：只食用不含奶蛋、植物五辛的純植物性製品 蛋素：食用全素或純素及蛋製品 植物五辛素：食用不含植物五辛（蔥、蒜、韭、蕎及興渠）的植物性製品 奶蛋素：食用全素或純素及奶蛋製品', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "669e3f56ea31", "answer_pdf_sha1": "44b27236efc3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 39, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-06998', 'dietitian', 'dietitian-moex-103-ad4b6c8a', 'sub-dietitian-02', NULL, 'single_choice', '有關塑化劑的敘述，下列何者錯誤？ 起雲劑是一種非法的食品添加物，可幫助食品的乳化 DEHP為一種磷苯二甲酸酯類化合物，是塑化劑 為避免塑化劑的危害，要養成多吃蔬果、多喝開水、多運動，加速塑化劑排出 不要用保鮮膜包裝油性食物，以避免塑化劑的暴露', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "669e3f56ea31", "answer_pdf_sha1": "44b27236efc3", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0304", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "團體膳食設計與管理", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 40, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
