  ('dietitian-moex-07001', 'dietitian', 'dietitian-moex-103-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '下列何種糖的甜度最高？ 果糖  葡萄糖  蔗糖  木醣醇', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "03a6384fb1e1", "answer_pdf_sha1": "661e03be9c00", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "營養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 1, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
