  ('dietitian-moex-07003', 'dietitian', 'dietitian-moex-103-cd594556', 'sub-dietitian-03', NULL, 'single_choice', '下列有關攝取過多膳食纖維的敘述，何者錯誤？ 每天攝食的膳食纖維超過50～60克就有可能危害健康 由於膳食纖維具有吸附水分和促進腸胃蠕動的特性，所以攝食過多也不會發生便秘 會增加痔瘡發生機會 會增加鐵、鈣等礦物質流失', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "03a6384fb1e1", "answer_pdf_sha1": "661e03be9c00", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0302", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "營養學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 3, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
